"use node";

import { action } from "./_generated/server";
import { v } from "convex/values";
import nodemailer from "nodemailer";

const LOGO_BASE64 = "";


export const sendOtpEmail = action({
  args: {
    email: v.string(),
    otp: v.string(),
  },
  handler: async (ctx, args) => {
    const transporter = nodemailer.createTransport({
      host: process.env.EMAIL_SERVER_HOST,
      port: Number(process.env.EMAIL_SERVER_PORT),
      secure: false, // true for 465, false for other ports (like 587)
      auth: {
        user: process.env.EMAIL_SERVER_USER,
        pass: process.env.EMAIL_SERVER_PASSWORD,
      },
    });

    const portalUrl = process.env.FRONTEND_URL || "http://localhost:3000";

    const mailOptions = {
      from: `"LUSL MIS Security" <${process.env.EMAIL_FROM_ADDRESS}>`,
      to: args.email,
      subject: "Security Verification Code - LUSL MIS",
      text: `Your LUSL MIS verification code is: ${args.otp}. This code will expire in 50 seconds. Do not share it.`,
      attachments: [
        {
          filename: "limkokwing_logo.jpg",
          content: Buffer.from(LOGO_BASE64, "base64"),
          cid: "limkokwing_logo"
        }
      ],
      html: `
        <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #e2e8f0; border-radius: 12px;">
          <div style="text-align: center; margin-bottom: 24px;">
            <div style="background-color: black; padding: 8px 12px; border-radius: 8px; border: 1px solid #e2e8f0; display: inline-block; margin-bottom: 8px; max-width: 160px; text-align: center;">
              <img src="cid:limkokwing_logo" alt="Limkokwing Logo" style="max-width: 100%; height: auto; display: block; margin: 0 auto;" />
            </div>
            <p style="color: #64748b; font-size: 11px; font-weight: bold; text-transform: uppercase; letter-spacing: 1px; margin: 4px 0 0 0;">LUSL MIS</p>
          </div>
          <div style="background-color: #f8fafc; padding: 32px; border-radius: 8px; text-align: center;">
            <p style="color: #475569; font-size: 16px; margin-bottom: 8px;">Multi-Factor Authentication Code</p>
            <h2 style="font-size: 36px; letter-spacing: 8px; margin: 0; color: #1e293b;">${args.otp}</h2>
            <p style="color: #94a3b8; font-size: 12px; margin-top: 16px;">⏱ This code expires in <b>50 seconds</b>. Do not share it with anyone.</p>
          </div>
          <div style="margin-top: 24px; color: #64748b; font-size: 12px; text-align: center;">
            <p>If you didn't request this code, please secure your account immediately.</p>
            <p>&copy; 2026 Limkokwing University Sierra Leone - Management Information System</p>
          </div>
        </div>
      `,
    };

    try {
      await transporter.sendMail(mailOptions);
      return { success: true };
    } catch (error) {
      console.error("Email delivery failed:", error);
      throw new Error("Failed to send verification email.");
    }
  },
});

export const sendWelcomeEmail = action({
  args: {
    name: v.string(),
    email: v.string(),
    role: v.string(),
    studentId: v.optional(v.string()),
    staffId: v.optional(v.string()),
    initialPassword: v.optional(v.string()),
    faculty: v.optional(v.string()),
    program: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const transporter = nodemailer.createTransport({
      host: process.env.EMAIL_SERVER_HOST,
      port: Number(process.env.EMAIL_SERVER_PORT),
      auth: {
        user: process.env.EMAIL_SERVER_USER,
        pass: process.env.EMAIL_SERVER_PASSWORD,
      },
    });

    const isStudent = args.role === "student";
    const subject = isStudent 
      ? "Welcome to Limkokwing University Sierra Leone!" 
      : "Welcome to Limkokwing University Sierra Leone - LUSL Staff";

    const portalUrl = process.env.FRONTEND_URL || "http://localhost:3000";

    const htmlContent = isStudent ? `
      <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e2e8f0; border-radius: 16px; overflow: hidden;">
        <div style="background-color: #0B192C; padding: 30px; text-align: center;">
          <div style="background-color: black; padding: 10px 14px; border-radius: 8px; border: 1px solid #1A2A40; display: inline-block; max-width: 170px; margin: 0 auto;">
            <img src="cid:limkokwing_logo" alt="Limkokwing Logo" style="max-width: 100%; height: auto; display: block; margin: 0 auto;" />
          </div>
          <h2 style="color: #10B981; margin: 10px 0 0 0; font-size: 18px; font-weight: 900; letter-spacing: 1px; text-transform: uppercase;">LUSL MIS</h2>
          <p style="color: white; margin: 4px 0 0 0; font-size: 13px; font-weight: bold;">Registration Complete</p>
        </div>
        <div style="padding: 32px;">
          <p style="font-size: 16px; color: #1e293b;">Dear <b>${args.name}</b>,</p>
          <p style="color: #475569; line-height: 1.6; margin-bottom: 20px;">
            Welcome to Limkokwing University Sierra Leone! Your academic profile has been successfully provisioned in the Management Information System. 
            ${args.faculty ? `You are officially welcomed as a student of the <b>${args.faculty}</b>.` : ''}
          </p>
          <div style="background-color: #f8fafc; padding: 24px; border-radius: 12px; margin: 24px 0; border: 1px dashed #cbd5e1;">
            <p style="margin: 0; font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: bold; tracking-wider: 1px;">Your Student ID Number</p>
            <p style="margin: 6px 0 14px 0; font-size: 22px; color: #2563eb; font-family: monospace; font-weight: bold;">${args.studentId}</p>
            
            <p style="margin: 0; font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: bold; tracking-wider: 1px;">Your Temporary Password</p>
            <p style="margin: 6px 0 14px 0; font-size: 16px; color: #334155; font-family: monospace; font-weight: bold;">${args.initialPassword || "Set by Administrator"}</p>

            ${args.faculty ? `
            <p style="margin: 0; font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: bold; tracking-wider: 1px;">Faculty Department</p>
            <p style="margin: 6px 0 14px 0; font-size: 14px; color: #1e293b; font-weight: bold;">${args.faculty}</p>
            ` : ''}

            ${args.program ? `
            <p style="margin: 0; font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: bold; tracking-wider: 1px;">Enrolled Program</p>
            <p style="margin: 6px 0 0 0; font-size: 14px; color: #1e293b; font-weight: bold;">${args.program}</p>
            ` : ''}
          </div>
          <p style="color: #475569;">You can now log in to the student portal using your institutional email and the temporary password above. Your initial tuition balance has been configured as per university policy.</p>
          <a href="${portalUrl}" style="display: inline-block; background-color: #2563eb; color: white; padding: 12px 24px; border-radius: 8px; text-decoration: none; font-weight: bold; margin-top: 16px;">Access Student Portal</a>
        </div>
      </div>
    ` : `
      <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e2e8f0; border-radius: 16px; overflow: hidden;">
        <div style="background-color: #0B192C; padding: 30px; text-align: center;">
          <div style="background-color: black; padding: 10px 14px; border-radius: 8px; border: 1px solid #1A2A40; display: inline-block; max-width: 170px; margin: 0 auto;">
            <img src="cid:limkokwing_logo" alt="Limkokwing Logo" style="max-width: 100%; height: auto; display: block; margin: 0 auto;" />
          </div>
          <h2 style="color: #10B981; margin: 10px 0 0 0; font-size: 18px; font-weight: 900; letter-spacing: 1px; text-transform: uppercase;">LUSL MIS</h2>
          <p style="color: white; margin: 4px 0 0 0; font-size: 13px; font-weight: bold;">Staff Onboarding</p>
        </div>
        <div style="padding: 32px;">
          <p style="font-size: 16px; color: #1e293b;">Hello <b>${args.name}</b>,</p>
          <p style="color: #10B981; font-size: 18px; font-weight: 700; margin: 8px 0 16px 0; line-height: 1.4;">Welcome to LUSL. We are now the staff of Limkokwing University.</p>
          <p style="color: #475569; line-height: 1.6; margin-bottom: 20px;">
            You have been successfully onboarded as a <b>${args.role.toUpperCase()}</b> member of the LUSL MIS team. Welcome to our mission.
          </p>
          <div style="background-color: #f8fafc; padding: 24px; border-radius: 12px; margin: 24px 0; border: 1px dashed #cbd5e1;">
            ${args.staffId ? `
            <p style="margin: 0; font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: bold; tracking-wider: 1px;">Your Staff ID Number</p>
            <p style="margin: 6px 0 14px 0; font-size: 22px; color: #10B981; font-family: monospace; font-weight: bold;">${args.staffId}</p>
            ` : ''}
            
            <p style="margin: 0; font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: bold; tracking-wider: 1px;">Your Temporary Password</p>
            <p style="margin: 6px 0 0 0; font-size: 16px; color: #334155; font-family: monospace; font-weight: bold;">${args.initialPassword || "Set by Administrator"}</p>
          </div>
          <p style="color: #475569;">Please log in using your official credentials and the temporary password above to begin your administrative duties. Ensure you follow all institutional data privacy protocols.</p>
          <a href="${portalUrl}" style="display: inline-block; background-color: #0B192C; color: white; padding: 12px 24px; border-radius: 8px; text-decoration: none; font-weight: bold; margin-top: 16px; border: 1px solid #1A2A40;">Access Team Portal</a>
          <div style="margin-top: 32px; padding-top: 24px; border-top: 1px solid #e2e8f0;">
            <p style="font-size: 12px; color: #94a3b8;">System: LUSL MIS v1.0<br/>Department: ${args.role.charAt(0).toUpperCase() + args.role.slice(1)}</p>
          </div>
        </div>
      </div>
    `;

    await transporter.sendMail({
      from: `"LUSL Registry" <${process.env.EMAIL_FROM_ADDRESS}>`,
      to: args.email,
      subject,
      html: htmlContent,
      attachments: [
        {
          filename: "limkokwing_logo.jpg",
          content: Buffer.from(LOGO_BASE64, "base64"),
          cid: "limkokwing_logo"
        }
      ]
    });
  },
});

export const sendDeferredStatusEmail = action({
  args: {
    email: v.string(),
    studentName: v.string(),
    modules: v.string(),
    status: v.union(v.literal("approved"), v.literal("rejected")),
    customMessage: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const transporter = nodemailer.createTransport({
      host: process.env.EMAIL_SERVER_HOST,
      port: Number(process.env.EMAIL_SERVER_PORT),
      secure: false, // true for 465, false for other ports
      auth: {
        user: process.env.EMAIL_SERVER_USER,
        pass: process.env.EMAIL_SERVER_PASSWORD,
      },
    });

    const isApproved = args.status === "approved";
    const subject = `Deferred Exam Application - ${args.status.toUpperCase()}`;
    const statusColor = isApproved ? "#10B981" : "#EF4444";
    const statusText = isApproved ? "APPROVED" : "DENIED";

    const portalUrl = process.env.FRONTEND_URL || "http://localhost:3000";

    const mailOptions = {
      from: `"LUSL Academic Registry" <${process.env.EMAIL_FROM_ADDRESS}>`,
      to: args.email,
      subject: subject,
      text: `Hello ${args.studentName},\n\nYour deferred exam application for module(s) [${args.modules}] has been ${statusText}.\n\nMessage: ${args.customMessage || "None"}\n\nPlease check your student portal for more details.\n\nAcademic Registry`,
      attachments: [
        {
          filename: "limkokwing_logo.jpg",
          content: Buffer.from(LOGO_BASE64, "base64"),
          cid: "limkokwing_logo"
        }
      ],
      html: `
        <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #e2e8f0; border-radius: 12px;">
          <div style="text-align: center; margin-bottom: 24px;">
            <div style="background-color: black; padding: 8px 12px; border-radius: 8px; border: 1px solid #e2e8f0; display: inline-block; margin-bottom: 8px; max-width: 160px; text-align: center;">
              <img src="cid:limkokwing_logo" alt="Limkokwing Logo" style="max-width: 100%; height: auto; display: block; margin: 0 auto;" />
            </div>
            <p style="color: #64748b; font-size: 11px; font-weight: bold; text-transform: uppercase; letter-spacing: 1px; margin: 4px 0 0 0;">LUSL MIS Academic Registry</p>
          </div>
          <div style="background-color: #f8fafc; padding: 32px; border-radius: 8px; text-align: left;">
            <h3 style="color: #1e293b; font-size: 18px; margin-top: 0;">Dear ${args.studentName},</h3>
            <p style="color: #475569; font-size: 14px; line-height: 1.6;">
              Your deferred exam application for module(s): <b>${args.modules}</b> has been processed by the Academic Registry.
            </p>
            <div style="margin: 24px 0; padding: 16px; border-left: 4px solid ${statusColor}; background-color: #ffffff; border-radius: 4px; border-top: 1px solid #f1f5f9; border-right: 1px solid #f1f5f9; border-bottom: 1px solid #f1f5f9;">
              <p style="margin: 0; font-size: 11px; font-weight: bold; color: #64748b; text-transform: uppercase;">Application Status</p>
              <h2 style="margin: 4px 0 0 0; color: ${statusColor}; font-size: 24px; font-weight: 800;">${statusText}</h2>
              
              ${args.customMessage ? `
              <p style="margin: 12px 0 0 0; font-size: 11px; font-weight: bold; color: #64748b; text-transform: uppercase;">Registry Remarks</p>
              <p style="margin: 4px 0 0 0; font-size: 13px; color: #334155; line-height: 1.5; font-style: italic;">"${args.customMessage}"</p>
              ` : ''}
            </div>
            <p style="color: #475569; font-size: 14px; line-height: 1.6;">
              ${isApproved 
                ? "You have been cleared to sit the exam for the listed module(s). Please log in to your student portal to access your updated deferment history and slip." 
                : "Your request has been denied. If you believe this is in error or have updated fee clearance from Finance, please contact the Academic Registry immediately."}
            </p>
            <a href="${portalUrl}" style="display: inline-block; background-color: #0B192C; color: white; padding: 12px 24px; border-radius: 8px; text-decoration: none; font-weight: bold; margin-top: 16px; border: 1px solid #1A2A40; font-size: 13px; text-align: center;">Access Student Portal</a>
          </div>
          <div style="margin-top: 24px; color: #64748b; font-size: 12px; text-align: center; border-top: 1px solid #f1f5f9; padding-top: 16px;">
            <p>This is an automated academic notification. Please do not reply directly to this email.</p>
            <p>&copy; 2026 Limkokwing University Sierra Leone - Management Information System</p>
          </div>
        </div>
      `,
    };

    await transporter.sendMail(mailOptions);
  },
});
